import 'dart:async'; import 'package:firebase_database/firebase_database.dart'; import 'package:injectable/injectable.dart'; import '../model/trusted_device.dart'; import '../../../core/constants/app_constants.dart'; @injectable class DeviceOnlineWatcher { final _db = FirebaseDatabase.instance; Stream<bool> watch(TrustedDevice device) => _db.ref('${AppConstants.presencePath}/${device.ownerUid}/${device.deviceId}/online').onValue.map((e) => e.snapshot.value as bool? ?? false); Future<bool> isOnline(TrustedDevice device) async { final snap = await _db.ref('${AppConstants.presencePath}/${device.ownerUid}/${device.deviceId}/online').get(); return snap.value as bool? ?? false; } }